            return this;
        }
        public boolean isPrecise() {
            return years().isPrecise()
                && months().isPrecise()
                && super.isPrecise();
        }
        public DurationField years() {
            return iYears;
        }
        public DurationField months() {
            return iMonths;
        }
        private Object readResolve() {
            return getPreciseYearMonthType();
        }
    }

